page.content:
{{groovy}}
def ns = "wiki:xwiki"
def id = (request.getParameter("id") ?: "").toString()
if (!id) { print "ERROR::missing-id"; return }
def ext = services.extension.getInstalledExtension(id, ns)
if (ext) {
  print "INSTALLED::${ext.id?.id}::${ext.id?.version}"
} else {
  print "MISSING::${id}"
}
{{/groovy}}
